import { useState } from 'preact/hooks';

interface ResetPasswordPanelProps {
  token: string;
  onClose: () => void;
}

export function ResetPasswordPanel({ token, onClose }: ResetPasswordPanelProps) {
  const [password, setPassword] = useState('');
  const [confirm, setConfirm] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e: Event) => {
    e.preventDefault();
    if (password !== confirm) {
      setError('PASSWORDS_MISMATCH: Data integrity check failed.');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const res = await fetch('/api/auth/reset-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token, newPassword: password }),
      });

      if (!res.ok) {
        const data = (await res.json()) as { error?: string };
        setError(data.error ?? 'RESET_FAILED: Uplink rejected.');
      } else {
        setSuccess(true);
      }
    } catch {
      setError('NETWORK_ERROR: Carrier lost.');
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div class="auth-modal-backdrop">
        <div class="auth-panel" role="dialog">
          <h3>ACCESS_RESTORED</h3>
          <p class="meta-tag" style="color: var(--color-green); margin-bottom: 1.5rem">
            CREDENTIALS_UPDATED: Your security protocol has been refreshed.
          </p>
          <button class="btn btn-primary" onClick={onClose}>
            RETURN_TO_LOGIN
          </button>
        </div>
      </div>
    );
  }

  return (
    <div
      class="auth-modal-backdrop"
      onClick={(e) => {
        if ((e.target as HTMLElement).classList.contains('auth-modal-backdrop')) onClose();
      }}
    >
      <div class="auth-panel" role="dialog">
        <h3>REESTABLISH_CREDENTIALS</h3>
        <p class="meta-tag" style="margin-bottom: 1rem">
          TOKEN_VALIDATED: Define new security sequence.
        </p>

        {error && (
          <p class="auth-error" role="alert">
            {error}
          </p>
        )}

        <form
          onSubmit={(e) => {
            void handleSubmit(e);
          }}
        >
          <div class="form-group">
            <label for="reset-password">New Password</label>
            <input
              id="reset-password"
              type="password"
              placeholder="Minimum 8 characters"
              value={password}
              onInput={(e) => {
                setPassword(e.currentTarget.value);
              }}
              required
              minLength={8}
            />
          </div>
          <div class="form-group">
            <label for="reset-confirm">Confirm Password</label>
            <input
              id="reset-confirm"
              type="password"
              placeholder="Re-enter password"
              value={confirm}
              onInput={(e) => {
                setConfirm(e.currentTarget.value);
              }}
              required
            />
          </div>
          <button type="submit" class="btn btn-primary" disabled={loading}>
            {loading ? 'PROCESSING...' : 'UPDATE_SECURITY_SEQUENCE'}
          </button>
        </form>
        <button class="btn-text" onClick={onClose}>
          CANCEL
        </button>
      </div>
    </div>
  );
}

import { mkdtemp, writeFile, rm } from 'node:fs/promises';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { describe, expect, it } from 'vitest';
import { generateScenario, GameScenarioSchema, loadScenario } from '../../bin/qa/scenario';

describe('QA scenario contract', () => {
  it('generates a schema-valid scenario with deterministic action content', () => {
    const scenario = generateScenario(42, 'classic', 20, 'bot-random', 'bot-heuristic');
    const parsed = GameScenarioSchema.parse(scenario);

    expect(parsed.version).toBe(1);
    expect(parsed.seed).toBe(42);
    expect(parsed.damageMode).toBe('classic');
    expect(parsed.startingLifepoints).toBe(20);
    expect(parsed.p1).toBe('bot-random');
    expect(parsed.p2).toBe('bot-heuristic');
    expect(parsed.actions.length).toBeGreaterThan(0);
    expect(parsed.actions[0]?.type).toBeDefined();
  });

  it('loads and validates a scenario file from disk', async () => {
    const tempDir = await mkdtemp(join(tmpdir(), 'phx-scenario-'));
    const scenarioPath = join(tempDir, 'scenario.json');
    const scenario = generateScenario(7, 'cumulative', 100, 'bot-heuristic', 'bot-heuristic');

    try {
      await writeFile(scenarioPath, `${JSON.stringify(scenario, null, 2)}\n`, 'utf8');

      const loaded = await loadScenario(scenarioPath);
      expect(loaded).toEqual(GameScenarioSchema.parse(scenario));
    } finally {
      await rm(tempDir, { recursive: true, force: true });
    }
  });
});

import { buildApp } from '../src/app.js';
import * as fs from 'node:fs/promises';
import * as path from 'node:path';

async function main() {
  // Build the app without binding to a port
  const app = await buildApp();
  await app.ready();

  // Extract the route tree from Fastify
  const routesText = app.printRoutes();

  const docPath = path.resolve(process.cwd(), '../docs/reference/api-routes.txt');

  // Ensure directory exists
  await fs.mkdir(path.dirname(docPath), { recursive: true });

  // Write to a text file
  await fs.writeFile(docPath, routesText, 'utf8');
  console.log(`✅ Routes dumped to ${docPath}`);

  await app.close();
}

main()
  .then(() => process.exit(0))
  .catch((err) => {
    console.error('Failed to dump routes:', err);
    process.exit(1);
  });

import { db } from './index.js';
import { matches, transactionLogs, users } from './schema.js';
import { and, desc, eq, asc, inArray, lt, or, isNull, sql } from 'drizzle-orm';
import type { MatchInstance, PlayerConnection, SpectatorMatchSummary } from '../match.js';
import type { WebSocket } from 'ws';
import type {
  GameState,
  Action,
  MatchEventLog,
  TransactionLogEntry,
  PhalanxEvent,
} from '@phalanxduel/shared';
import type { GameConfig } from '@phalanxduel/engine';
import { traceDbQuery } from './observability.js';
import { TelemetryName } from '@phalanxduel/shared';
import { SeverityNumber } from '@opentelemetry/api-logs';
import { emitOtlpLog } from '../instrument.js';

function isLifecycleEvent(event: PhalanxEvent): boolean {
  return (
    event.name === 'match.created' ||
    event.name === 'player.joined' ||
    event.name === TelemetryName.EVENT_PLAYER_DISCONNECTED ||
    event.name === TelemetryName.EVENT_PLAYER_RECONNECTED ||
    event.name === 'game.initialized' ||
    event.name === 'game.completed'
  );
}

export interface MatchSummary {
  matchId: string;
  playerIds: (string | null)[];
  playerNames: (string | null)[];
  winnerIndex: number | null;
  victoryType: string | null;
  turnCount: number | null;
  fingerprint: string | null;
  createdAt: string;
  completedAt: string;
}

export interface UserActiveMatchSummary {
  matchId: string;
  playerId: string;
  playerIndex: 0 | 1;
  opponentName: string | null;
  botStrategy: 'random' | 'heuristic' | null;
  status: 'pending' | 'active';
  phase: string | null;
  turnNumber: number | null;
  createdAt: string;
  updatedAt: string;
}

export interface CompletedMatchHistoryEntry {
  matchId: string;
  player1Name: string;
  player2Name: string;
  winnerName: string | null;
  totalTurns: number;
  isPvP: boolean;
  humanPlayerCount: number;
  completedAt: string;
  durationMs: number | null;
}

export interface CompletedMatchHistoryPage {
  matches: CompletedMatchHistoryEntry[];
  total: number;
}

interface RecoverPlayerParams {
  playerName: string | null;
  playerId: string;
  playerIndex: 0 | 1;
  userId: string | null;
  socket: WebSocket | null;
  disconnectedAt?: string;
}

function recoverPlayer({
  playerName,
  playerId,
  playerIndex,
  userId,
  socket,
  disconnectedAt,
}: RecoverPlayerParams): PlayerConnection | null {
  if (!playerName) return null;
  return {
    playerId,
    playerName,
    playerIndex,
    userId: userId ?? undefined,
    socket,
    disconnectedAt,
  };
}

function recoverDisconnectedAtByPlayer(
  row: typeof matches.$inferSelect,
): Partial<Record<0 | 1, string>> {
  const persistedEventLog = row.eventLog as MatchEventLog | null;
  const disconnectedAtByPlayer: Partial<Record<0 | 1, string>> = {};

  for (const event of persistedEventLog?.events ?? []) {
    if (
      event.name !== TelemetryName.EVENT_PLAYER_DISCONNECTED &&
      event.name !== TelemetryName.EVENT_PLAYER_RECONNECTED
    ) {
      continue;
    }

    const payload = event.payload as { playerIndex?: number; disconnectedAt?: string } | null;
    const playerIndex = payload?.playerIndex;
    if (playerIndex !== 0 && playerIndex !== 1) continue;

    if (event.name === TelemetryName.EVENT_PLAYER_DISCONNECTED) {
      disconnectedAtByPlayer[playerIndex] = payload?.disconnectedAt ?? event.timestamp;
      continue;
    }

    delete disconnectedAtByPlayer[playerIndex];
  }

  return disconnectedAtByPlayer;
}

function recoverPlayers(
  row: typeof matches.$inferSelect,
  config: GameConfig | null,
): MatchInstance['players'] {
  const playerConfig = config?.players ?? [];
  const player0Id = playerConfig[0]?.id ?? (row.player1Id || 'recovered-p1');
  const player1Id = playerConfig[1]?.id ?? (row.player2Id || 'recovered-p2');
  const disconnectedAtByPlayer = recoverDisconnectedAtByPlayer(row);

  const players: [PlayerConnection | null, PlayerConnection | null] = [
    recoverPlayer({
      playerName: row.player1Name,
      playerId: player0Id,
      playerIndex: 0,
      userId: row.player1Id,
      socket: null,
      disconnectedAt: disconnectedAtByPlayer[0],
    }),
    recoverPlayer({
      playerName: row.player2Name,
      playerId: player1Id,
      playerIndex: 1,
      userId: row.player2Id,
      socket: null,
      disconnectedAt: disconnectedAtByPlayer[1],
    }),
  ];

  return players;
}

function recoverLifecycleEvents(row: typeof matches.$inferSelect) {
  const persistedEventLog = row.eventLog as MatchEventLog | null;
  return persistedEventLog?.events.filter(isLifecycleEvent) ?? [];
}

function buildRecoveredMatch(row: typeof matches.$inferSelect): MatchInstance {
  const config = row.config as GameConfig | null;
  const botStrategy = row.botStrategy ?? undefined;

  return {
    matchId: row.id,
    visibility: (row.visibility ?? 'private') as MatchInstance['visibility'],
    publicStatus: row.publicStatus as MatchInstance['publicStatus'],
    publicExpiresAt: row.publicExpiresAt?.toISOString?.() ?? null,
    minPublicRating: row.minPublicRating ?? null,
    maxPublicRating: row.maxPublicRating ?? null,
    minGamesPlayed: row.minGamesPlayed ?? null,
    requiresEstablishedRating: row.requiresEstablishedRating,
    players: recoverPlayers(row, config),
    spectators: [],
    state: row.state as GameState,
    config,
    actionHistory: row.actionHistory as Action[],
    gameOptions: config?.gameOptions,
    rngSeed: config?.rngSeed,
    matchParams: config?.matchParams,
    botConfig:
      botStrategy && config
        ? {
            strategy: botStrategy,
            seed: config.rngSeed,
          }
        : undefined,
    botPlayerIndex: botStrategy ? 1 : undefined,
    lastPreState: null,
    lifecycleEvents: recoverLifecycleEvents(row),
    createdAt: row.createdAt.getTime(),
    lastActivityAt: row.updatedAt.getTime(),
    botStrategy,
  };
}

function buildUserActiveMatchSummary(
  row: typeof matches.$inferSelect,
  userId: string,
): UserActiveMatchSummary | null {
  const playerIndex = row.player1Id === userId ? 0 : row.player2Id === userId ? 1 : null;
  if (playerIndex === null) return null;

  const config = row.config as GameConfig | null;
  const state = row.state as GameState | null;
  const playerId = config?.players?.[playerIndex]?.id;
  if (!playerId) return null;

  const opponentName =
    playerIndex === 0
      ? (row.player2Name ?? (row.botStrategy ? `Bot (${row.botStrategy})` : null))
      : row.player1Name;

  return {
    matchId: row.id,
    playerId,
    playerIndex,
    opponentName,
    botStrategy: row.botStrategy ?? null,
    status: row.status === 'pending' ? 'pending' : 'active',
    phase: state?.phase ?? null,
    turnNumber: state?.turnNumber ?? null,
    createdAt: row.createdAt.toISOString(),
    updatedAt: row.updatedAt.toISOString(),
  };
}

function buildFallbackConfig(match: MatchInstance) {
  return {
    matchId: match.matchId,
    players: [
      {
        id: match.players[0]?.playerId ?? 'pending',
        name: match.players[0]?.playerName ?? 'Waiting...',
      },
      {
        id: match.players[1]?.playerId ?? 'pending',
        name: match.players[1]?.playerName ?? 'Waiting...',
      },
    ],
    rngSeed: match.rngSeed ?? 0,
    matchParams: match.matchParams || {
      rows: 6,
      columns: 7,
      maxHandSize: 12,
      initialDraw: 12,
    },
  };
}

export class MatchRepository {
  private async verifyUserIds(
    p1Id: string | null,
    p2Id: string | null,
  ): Promise<[string | null, string | null]> {
    if (!p1Id && !p2Id) return [null, null];

    const database = db;
    if (!database) return [null, null];

    try {
      const ids = [p1Id, p2Id].filter((id): id is string => !!id);
      const existingUsers = await traceDbQuery(
        'db.matches.verify_users',
        { operation: 'SELECT', table: 'users' },
        () => database.select({ id: users.id }).from(users).where(inArray(users.id, ids)),
      );
      const validIds = new Set(existingUsers.map((u) => u.id));
      return [p1Id && validIds.has(p1Id) ? p1Id : null, p2Id && validIds.has(p2Id) ? p2Id : null];
    } catch (err) {
      console.warn('MatchRepo: failed to verify users, falling back to null IDs:', err);
      return [null, null];
    }
  }

  async saveMatch(match: MatchInstance): Promise<void> {
    const database = db;
    if (!database) return;

    // We allow saving matches even without a config (pending state) to ensure the
    // match record exists in the DB before any ledger actions are written.

    // Verify user existence if IDs are provided to avoid FK violations (GHOST_USER protection)
    const [p1Id, p2Id] = await this.verifyUserIds(
      match.players[0]?.userId ?? null,
      match.players[1]?.userId ?? null,
    );

    const payload = this.prepareMatchPayload(match, p1Id, p2Id);

    try {
      await traceDbQuery(
        'db.matches.upsert',
        {
          operation: 'UPSERT',
          table: 'matches',
        },
        () =>
          database
            .insert(matches)
            .values({
              ...payload,
              createdAt: new Date(match.createdAt),
            })
            .onConflictDoUpdate({
              target: matches.id,
              set: payload,
            }),
      );
    } catch (err) {
      console.error(`[MatchRepo] CRITICAL: Failed to save match ${match.matchId}:`, err);
      throw err;
    }
  }

  async claimPublicOpenMatch(params: {
    matchId: string;
    player2Id: string | null;
    player2Name: string;
  }): Promise<boolean> {
    const database = db;
    if (!database) return false;

    try {
      const rows = await traceDbQuery(
        'db.matches.claim_public_open',
        {
          operation: 'UPDATE',
          table: 'matches',
        },
        () =>
          database
            .update(matches)
            .set({
              player2Id: params.player2Id,
              player2Name: params.player2Name,
              publicStatus: 'claimed',
              publicExpiresAt: null,
              updatedAt: new Date(),
            })
            .where(
              and(
                eq(matches.id, params.matchId),
                eq(matches.visibility, 'public_open'),
                eq(matches.publicStatus, 'open'),
                isNull(matches.player2Id),
              ),
            )
            .returning({ id: matches.id }),
      );
      return rows.length > 0;
    } catch (err) {
      emitOtlpLog(SeverityNumber.ERROR, 'ERROR', 'Failed to claim public open match', {
        'db.operation': 'claimPublicOpenMatch',
        'error.message': err instanceof Error ? err.message : String(err),
      });
      return false;
    }
  }

  private prepareMatchPayload(match: MatchInstance, p1Id: string | null, p2Id: string | null) {
    const status = (
      match.state ? (match.state.phase === 'gameOver' ? 'completed' : 'active') : 'pending'
    ) as 'pending' | 'active' | 'completed' | 'cancelled';

    return {
      id: match.matchId,
      player1Id: p1Id,
      player2Id: p2Id,
      visibility: match.visibility ?? 'private',
      publicStatus: match.publicStatus ?? null,
      publicExpiresAt: match.publicExpiresAt ? new Date(match.publicExpiresAt) : null,
      minPublicRating: match.minPublicRating ?? null,
      maxPublicRating: match.maxPublicRating ?? null,
      minGamesPlayed: match.minGamesPlayed ?? null,
      requiresEstablishedRating: match.requiresEstablishedRating ?? false,
      player1Name: match.players[0]?.playerName ?? null,
      player2Name: match.players[1]?.playerName ?? null,
      botStrategy: match.botStrategy ?? null,
      config: match.config ?? buildFallbackConfig(match),
      state: match.state,
      actionHistory: match.actionHistory,
      transactionLog: match.state?.transactionLog ?? [],
      outcome: match.state?.outcome ?? null,
      status,
      updatedAt: new Date(),
    };
  }

  async getCompletedMatches(page: number, limit: number): Promise<MatchSummary[]> {
    const database = db;
    if (!database) return [];

    try {
      const offset = (page - 1) * limit;
      const rows = await traceDbQuery(
        'db.matches.select_completed',
        { operation: 'SELECT', table: 'matches' },
        () =>
          database
            .select({
              id: matches.id,
              player1Id: matches.player1Id,
              player2Id: matches.player2Id,
              player1Name: matches.player1Name,
              player2Name: matches.player2Name,
              outcome: matches.outcome,
              eventLogFingerprint: matches.eventLogFingerprint,
              createdAt: matches.createdAt,
              updatedAt: matches.updatedAt,
            })
            .from(matches)
            .where(eq(matches.status, 'completed'))
            .orderBy(desc(matches.createdAt))
            .limit(limit)
            .offset(offset),
      );

      return rows.map((row) => {
        const outcome = row.outcome as {
          winnerIndex?: number | null;
          victoryType?: string | null;
          turnNumber?: number | null;
        } | null;
        return {
          matchId: row.id,
          playerIds: [row.player1Id ?? null, row.player2Id ?? null],
          playerNames: [row.player1Name, row.player2Name],
          winnerIndex: outcome?.winnerIndex ?? null,
          victoryType: outcome?.victoryType ?? null,
          turnCount: outcome?.turnNumber ?? null,
          fingerprint: row.eventLogFingerprint ?? null,
          createdAt: row.createdAt.toISOString(),
          completedAt: row.updatedAt.toISOString(),
        };
      });
    } catch (err) {
      emitOtlpLog(SeverityNumber.ERROR, 'ERROR', 'Failed to get completed matches', {
        'db.operation': 'getCompletedMatches',
        'error.message': err instanceof Error ? err.message : String(err),
      });
      return [];
    }
  }

  async listCompletedMatchHistory(
    page: number,
    pageSize: number,
    playerId?: string,
  ): Promise<CompletedMatchHistoryPage> {
    const database = db;
    if (!database) return { matches: [], total: 0 };

    try {
      const offset = (page - 1) * pageSize;
      const whereClause = playerId
        ? and(
            eq(matches.status, 'completed'),
            or(eq(matches.player1Id, playerId), eq(matches.player2Id, playerId)),
          )
        : eq(matches.status, 'completed');

      const [rows, totalRows] = await Promise.all([
        traceDbQuery(
          'db.matches.select_completed_history',
          { operation: 'SELECT', table: 'matches' },
          () =>
            database
              .select({
                id: matches.id,
                player1Name: matches.player1Name,
                player2Name: matches.player2Name,
                botStrategy: matches.botStrategy,
                state: matches.state,
                outcome: matches.outcome,
                createdAt: matches.createdAt,
                updatedAt: matches.updatedAt,
              })
              .from(matches)
              .where(whereClause)
              .orderBy(desc(matches.updatedAt))
              .limit(pageSize)
              .offset(offset),
        ),
        traceDbQuery(
          'db.matches.count_completed_history',
          { operation: 'SELECT', table: 'matches' },
          () =>
            database
              .select({ count: sql<number>`COUNT(*)::int` })
              .from(matches)
              .where(whereClause),
        ),
      ]);

      return {
        matches: rows.map((row) => {
          const state = row.state as GameState | null;
          const outcome = row.outcome as GameState['outcome'] | null;
          const winnerIndex = outcome?.winnerIndex ?? state?.outcome?.winnerIndex ?? null;
          const playerNames = [row.player1Name ?? 'Player 1', row.player2Name ?? 'Player 2'];

          const isPvP = row.botStrategy == null;
          const humanPlayerCount = isPvP ? 2 : 1; // Completed matches always have 2 players seated

          return {
            matchId: row.id,
            player1Name: playerNames[0] ?? 'Player 1',
            player2Name: playerNames[1] ?? 'Player 2',
            winnerName:
              winnerIndex === 0 || winnerIndex === 1 ? (playerNames[winnerIndex] ?? null) : null,
            totalTurns: outcome?.turnNumber ?? state?.outcome?.turnNumber ?? state?.turnNumber ?? 0,
            isPvP,
            humanPlayerCount,
            completedAt: row.updatedAt.toISOString(),
            durationMs: row.updatedAt.getTime() - row.createdAt.getTime(),
          };
        }),
        total: totalRows[0]?.count ?? 0,
      };
    } catch (err) {
      emitOtlpLog(SeverityNumber.ERROR, 'ERROR', 'Failed to list completed match history', {
        'db.operation': 'listCompletedMatchHistory',
        'error.message': err instanceof Error ? err.message : String(err),
      });
      return { matches: [], total: 0 };
    }
  }

  async listActiveMatchesForUser(userId: string): Promise<UserActiveMatchSummary[]> {
    const database = db;
    if (!database) return [];

    try {
      const rows = await traceDbQuery(
        'db.matches.select_active_for_user',
        { operation: 'SELECT', table: 'matches' },
        () =>
          database
            .select()
            .from(matches)
            .where(or(eq(matches.player1Id, userId), eq(matches.player2Id, userId)))
            .orderBy(desc(matches.updatedAt)),
      );

      return rows
        .filter((row) => row.status === 'pending' || row.status === 'active')
        .map((row) => buildUserActiveMatchSummary(row, userId))
        .filter((row): row is UserActiveMatchSummary => row !== null);
    } catch (err) {
      emitOtlpLog(SeverityNumber.ERROR, 'ERROR', 'Failed to list active matches for user', {
        'db.operation': 'listActiveMatchesForUser',
        'error.message': err instanceof Error ? err.message : String(err),
        'user.id': userId,
      });
      return [];
    }
  }

  async listSpectatorMatches(): Promise<SpectatorMatchSummary[]> {
    const database = db;
    if (!database) return [];

    try {
      const rows = await traceDbQuery(
        'db.matches.select_spectator_lobby',
        { operation: 'SELECT', table: 'matches' },
        () =>
          database
            .select({
              id: matches.id,
              status: matches.status,
              player1Name: matches.player1Name,
              player2Name: matches.player2Name,
              botStrategy: matches.botStrategy,
              state: matches.state,
              createdAt: matches.createdAt,
              updatedAt: matches.updatedAt,
            })
            .from(matches)
            .where(or(eq(matches.status, 'pending'), eq(matches.status, 'active')))
            .orderBy(desc(matches.updatedAt)),
      );

      return rows
        .map((row): SpectatorMatchSummary | null => {
          const hasP1 = row.player1Name !== null;
          const hasP2 = row.player2Name !== null;
          if (!hasP1 && !hasP2) return null;
          const status = hasP1 && hasP2 && row.status === 'active' ? 'active' : 'waiting';
          if (status === 'waiting' && hasP1 && hasP2) return null;
          const state = row.state as GameState | null;

          const playerCount = (hasP1 ? 1 : 0) + (hasP2 ? 1 : 0);
          const isPvP = row.botStrategy == null;
          const humanPlayerCount = isPvP ? playerCount : 1;

          return {
            matchId: row.id,
            status,
            phase: status === 'active' ? (state?.phase ?? null) : null,
            turnNumber: status === 'active' ? (state?.turnNumber ?? null) : null,
            player1Name: row.player1Name,
